// Generate CRUD API from schema
const schema = {
  resource: 'products',
  fields: ['id', 'name', 'price', 'category', 'stock'],
  auth: 'jwt'
};

const endpoints = [
  { method: 'GET', path: `/api/v1/${schema.resource}`, handler: 'list' },
  { method: 'GET', path: `/api/v1/${schema.resource}/:id`, handler: 'get' },
  { method: 'POST', path: `/api/v1/${schema.resource}`, handler: 'create' },
  { method: 'PUT', path: `/api/v1/${schema.resource}/:id`, handler: 'update' },
  { method: 'DELETE', path: `/api/v1/${schema.resource}/:id`, handler: 'delete' }
];

const code = `const express = require('express');
const router = express.Router();
const { ${schema.fields.join(', ')} } = require('./models/${schema.resource}');

${endpoints.map(e => `
// ${e.method} ${e.path}
router.${e.method.toLowerCase()}('${e.path.replace(`/${schema.resource}/:id`, '')}/:id?', async (req, res) => {
  try {
    const { id } = req.params;
    const body = req.body;
    let result;
    switch (req.method) {
      case 'GET':
        result = id ? await ${schema.resource}.findById(id) : await ${schema.resource}.findAll(req.query);
        break;
      case 'POST':
        result = await ${schema.resource}.create(body);
        break;
      case 'PUT':
        result = await ${schema.resource}.update(id, body);
        break;
      case 'DELETE':
        result = await ${schema.resource}.delete(id);
        break;
    }
    res.status(200).json({ data: result });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});`).join('')}

module.exports = router;`;

return [{ json: { schema, endpoints, code } }];

// Generate OpenAPI 3.0 spec from schema
const data = $input.first().json;
const spec = {
  openapi: '3.0.3',
  info: { title: `${data.schema.resource} API`, version: '1.0.0' },
  paths: {}
};

for (const endpoint of data.endpoints) {
  const path = endpoint.path.replace(':id', '{id}');
  spec.paths[path] = {
    [endpoint.method.toLowerCase()]: {
      summary: `${endpoint.method} ${data.schema.resource}`,
      responses: { '200': { description: 'Success' } }
    }
  };
}

return [{ json: { spec } }];
